import{m as a,aU as s,z as p,M as t}from"./chunks/framework.LN92DB6A.js";const r=JSON.parse('{"title":"外地车转广州新能源车牌","description":"经常跑广州的外地新能源车主，转广州牌的流程其实很简单，自己办理安心还能省几百大洋。","frontmatter":{"title":"外地车转广州新能源车牌","tags":["新能源","车牌"],"categories":["办事攻略"],"date":"2024-02-20T00:00:00.000Z","description":"经常跑广州的外地新能源车主，转广州牌的流程其实很简单，自己办理安心还能省几百大洋。","references":[{"title":"知乎原文","url":"https://zhuanlan.zhihu.com/p/678041376"}],"head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/car-transfer"}]]},"headers":[],"relativePath":"posts/2026/car-transfer.md","filePath":"posts/2026/car-transfer.md","lastUpdated":1779868425000}');const e=a({name:"posts/2026/car-transfer.md"},[["render",function(a,r,e,i,l,n){return s(),p("div",null,[...r[0]||(r[0]=[t('<p>经常跑广州的外地新能源车主，转广州牌的流程其实很简单。当然 4S 店有合作的&quot;黄牛&quot;代办，费用几百不等，你的车和身份证都要交给人家，实在不放心且有时间的话可以自己办理，安心还能省几百大洋，流程我整理好了如下：</p><h2 id="_1-申请广州新能源指标并打印" tabindex="-1">1. 申请广州新能源指标并打印 <a class="header-anchor" href="#_1-申请广州新能源指标并打印" aria-label="Permalink to &quot;1. 申请广州新能源指标并打印&quot;">​</a></h2><p>访问广州市中小客车指标调控管理信息系统：<a href="https://apply.jtj.gz.gov.cn/apply" target="_blank" rel="noreferrer">https://apply.jtj.gz.gov.cn/apply</a> 注册并登录</p><p>找到**「其他指标 ——新能源指标——去申请——输入短信随机码——填写车辆信息（型号和车架号）——提交生成」**</p><p>提交信息时需要选择你的车型对应的新能源目录，不知道的可以问销售，也可以点击蓝色按钮&quot;产品型号/车辆型号查询&quot;</p><p><em>注意：该系统的短信验证码一段时间内只会发送一条，可以重复使用。</em></p><p><a class="img-fancybox" href="/images/car-transfer-01.webp" data-fancybox="gallery" data-caption="新能源指标申请页面"><img class="post-img" src="/images/car-transfer-01.webp" alt="新能源指标申请页面" loading="lazy"><span class="post-img-tip">新能源指标申请页面</span></a></p><p>比如我的是比亚迪宋，型号是BYD6471****，查询结果如下：</p><p><a class="img-fancybox" href="/images/car-transfer-02.webp" data-fancybox="gallery" data-caption="车型查询结果"><img class="post-img" src="/images/car-transfer-02.webp" alt="车型查询结果" loading="lazy"><span class="post-img-tip">车型查询结果</span></a></p><p>根据查到的一个个测试，对应不上系统会报错的，最终结果如下，车架号填你自己的</p><p><a class="img-fancybox" href="/images/car-transfer-03.webp" data-fancybox="gallery" data-caption="填写车辆信息"><img class="post-img" src="/images/car-transfer-03.webp" alt="填写车辆信息" loading="lazy"><span class="post-img-tip">填写车辆信息</span></a></p><p>申请完了打印出来即可，一般是隔天生效，有效期一年。</p><h2 id="_2-广州交警-公众号预约时间" tabindex="-1">2. &quot;广州交警&quot;公众号预约时间 <a class="header-anchor" href="#_2-广州交警-公众号预约时间" aria-label="Permalink to &quot;2. &quot;广州交警&quot;公众号预约时间&quot;">​</a></h2><p>指标申请后第二天在微信公众号&quot;广州交警&quot;上预约时间，选择「业务办理——车管服务大厅——业务预约——人脸识别——车辆登记业务——中小客车变更登记——居住地址变更迁入」填写好信息预约时间地点。</p><p><a class="img-fancybox" href="/images/car-transfer-04.webp" data-fancybox="gallery" data-caption="广州交警公众号预约"><img class="post-img" src="/images/car-transfer-04.webp" alt="广州交警公众号预约" loading="lazy"><span class="post-img-tip">广州交警公众号预约</span></a></p><h2 id="_3-准备好材料前往车管所" tabindex="-1">3. 准备好材料前往车管所 <a class="header-anchor" href="#_3-准备好材料前往车管所" aria-label="Permalink to &quot;3. 准备好材料前往车管所&quot;">​</a></h2><p>绿本抵押和找人代理需要额外材料，这里不做描述。只针对本人未抵押登记的情况（绿本在你手里）</p><ul><li>身份证原件，现场会问你要身份证复印件，不用管，没有他会帮你打印</li><li>第一步申请的新能源指标书打印件</li><li>行驶证、车辆登记证书（绿本）</li></ul><p>没了，其他不需要了，你没有看错。</p><h2 id="_4-办理流程" tabindex="-1">4. 办理流程 <a class="header-anchor" href="#_4-办理流程" aria-label="Permalink to &quot;4. 办理流程&quot;">​</a></h2><p>这里以广州车管所番禺分所机动车业务厅和教考场为例。</p><p>先去照相区找工作人员给你的车照相，然后去到拓印区拓印。</p><p><a class="img-fancybox" href="/images/car-transfer-05.webp" data-fancybox="gallery" data-caption="照相区"><img class="post-img" src="/images/car-transfer-05.webp" alt="照相区" loading="lazy"><span class="post-img-tip">照相区</span></a></p><p>拓印完了找个位置停车，去取刚才拍好的照片。</p><p><a class="img-fancybox" href="/images/car-transfer-06.webp" data-fancybox="gallery" data-caption="取相处，拍的有点模糊"><img class="post-img" src="/images/car-transfer-06.webp" alt="取相处，拍的有点模糊" loading="lazy"><span class="post-img-tip">取相处，拍的有点模糊</span></a></p><p>拿完照片后去用身份证签到（全程只用签到一次，无需其他取号之类的操作），签到后交材料。身份证原件核实后会还给你。</p><p><a class="img-fancybox" href="/images/car-transfer-07.webp" data-fancybox="gallery" data-caption="签到交材料"><img class="post-img" src="/images/car-transfer-07.webp" alt="签到交材料" loading="lazy"><span class="post-img-tip">签到交材料</span></a></p><p>提交材料后工作人员会整理好材料给你，拿着你的材料开车去机动车查验场处验车，验车记得不熄火，放好三脚架，打开引擎盖。</p><p><a class="img-fancybox" href="/images/car-transfer-08.webp" data-fancybox="gallery" data-caption="验车"><img class="post-img" src="/images/car-transfer-08.webp" alt="验车" loading="lazy"><span class="post-img-tip">验车</span></a></p><p>验车完了之后，工作人员会把材料收走。这个时候找个位置停车，去机动车业务大厅&quot;车辆登记业务&quot;窗口等他们叫名字，过号屏幕会显示你的名字，耐心等待叫名即可，等待时间可能要半个小时至一个小时。</p><p><a class="img-fancybox" href="/images/car-transfer-09.webp" data-fancybox="gallery" data-caption="等待叫号"><img class="post-img" src="/images/car-transfer-09.webp" alt="等待叫号" loading="lazy"><span class="post-img-tip">等待叫号</span></a></p><p>叫到名字后就是填资料拍照交钱（120元工本费）填写快递信息，然后去选号窗口选号。</p><p>选号完了就开车去拓印区拆牌点那里拆下你的旧牌，那里有工具的。</p><p><a class="img-fancybox" href="/images/car-transfer-10.webp" data-fancybox="gallery" data-caption="拆牌"><img class="post-img" src="/images/car-transfer-10.webp" alt="拆牌" loading="lazy"><span class="post-img-tip">拆牌</span></a></p><p>拆牌后拿着旧牌去领证窗口，上交旧牌拿临牌。行驶证和新牌和车辆登记证书都是邮政到付寄给你（快递费35 + 25），当然你也可以选择自取。</p><p>至此所有流程结束，回家等新牌就可以了，整个车管所办理流程花费我两小时。</p>',36)])])}]]);export{r as __pageData,e as default};
